// Last-write-wins (LWW) — simple, can lose concurrent writes
// Cassandra default: higher timestamp wins
INSERT INTO user_profile (id, name, updated_at)
VALUES (42, 'Alice', toTimestamp(now()));
-- If two nodes wrote concurrently, the later timestamp wins
-- The earlier write is silently discarded — potential data loss

