// CRDT example: G-Counter (grow-only, merge-safe)
public class GCounter {
    private final Map<String, Long> counts = new HashMap<>();
    private final String nodeId;

    public void increment() {
        counts.merge(nodeId, 1L, Long::sum);
    }

    public long value() { return counts.values().stream().mapToLong(Long::longValue).sum(); }

    // Merge from another replica — always correct, no conflicts
    public GCounter merge(GCounter other) {
        GCounter result = new GCounter(nodeId);
        Set<String> allNodes = new HashSet<>(counts.keySet());
        allNodes.addAll(other.counts.keySet());
        allNodes.forEach(n -> result.counts.put(n,
            Math.max(counts.getOrDefault(n, 0L),
                     other.counts.getOrDefault(n, 0L))));
        return result;
    }
}

