// Saga — choreography style (event-driven)
// Step 1: OrderService creates order → publishes OrderCreated
ordersDB.save(order);  // local transaction
kafka.send("order.created", event);

// Step 2: PaymentService charges → publishes PaymentCompleted
// (or publishes PaymentFailed if charge fails)
@KafkaListener(topics = "order.created")
void onOrderCreated(OrderCreatedEvent e) {
    try {
        payment.charge(e.amount());
        kafka.send("payment.completed", new PaymentCompletedEvent(e.orderId()));
    } catch (PaymentException ex) {
        kafka.send("payment.failed", new PaymentFailedEvent(e.orderId()));
    }
}

// Compensating transaction if payment fails:
@KafkaListener(topics = "payment.failed")
void onPaymentFailed(PaymentFailedEvent e) {
    orderService.cancelOrder(e.orderId()); // compensating action
}

// Resilience4j Circuit Breaker
@Bean
public CircuitBreaker paymentCircuitBreaker(CircuitBreakerRegistry registry) {
    CircuitBreakerConfig config = CircuitBreakerConfig.custom()
        .failureRateThreshold(50)          // open at 50% failure rate
        .waitDurationInOpenState(Duration.ofSeconds(30))
        .slidingWindowSize(10)             // evaluate last 10 calls
        .permittedNumberOfCallsInHalfOpenState(3)
        .build();
    return registry.circuitBreaker("payment", config);
}

// Applying the circuit breaker
public PaymentResult charge(Order order) {
    CircuitBreaker cb = circuitBreakerRegistry.circuitBreaker("payment");
    return cb.executeSupplier(() -> paymentClient.charge(order));
}

// With fallback
public PaymentResult charge(Order order) {
    return Try.ofSupplier(
        CircuitBreaker.decorateSupplier(cb, () -> paymentClient.charge(order))
    ).recover(CallNotPermittedException.class,
              ex -> PaymentResult.pending("Payment service unavailable, will retry")
    ).get();
}

// Spring Boot: @CircuitBreaker annotation
@CircuitBreaker(name = "payment", fallbackMethod = "paymentFallback")
public PaymentResult charge(Order order) { return paymentClient.charge(order); }
private PaymentResult paymentFallback(Order order, Exception ex) {
    return PaymentResult.pending("Queued for retry");
}

// Bulkhead — separate thread pools per dependency
BulkheadConfig config = BulkheadConfig.custom()
    .maxConcurrentCalls(10)    // max 10 concurrent calls to payment
    .maxWaitDuration(Duration.ofMillis(100))
    .build();
Bulkhead paymentBulkhead = Bulkhead.of("payment", config);

// All payment calls go through this bulkhead
paymentBulkhead.executeSupplier(() -> paymentClient.charge(order));
// If 10 threads are already in payment, the 11th waits 100ms then fails
// The rest of the application (inventory, orders) is unaffected

